module req_ack_handshake(input clk,input rst_n,input req,output ack);
 reg [1:0] s; localparam IDLE=0,WORK=1,RESP=2;
 assign ack = (s==RESP);
 always @(posedge clk or negedge rst_n) begin
  if(!rst_n) s<=IDLE;
  else case(s)
   IDLE: s<= req?WORK:IDLE;
   WORK: s<=RESP;
   RESP: s<= req?RESP:IDLE;
   default: s<=IDLE;
  endcase
 end
endmodule

