module sync_fifo4(input clk,input rst_n,input wr,input rd,input [7:0] din,
                 output [7:0] dout,output full,output empty);
 reg [7:0] mem [0:3]; reg [2:0] cnt; reg [1:0] wp,rp;
 assign empty=(cnt==0); assign full=(cnt==4); assign dout=mem[rp];
 wire w = wr && (cnt!=4);
 wire r = rd && (cnt!=0);
 always @(posedge clk or negedge rst_n) begin
  if(!rst_n) begin cnt<=0; wp<=0; rp<=0; end
  else begin
   case({w,r})
    2'b10: begin mem[wp]<=din; wp<=wp+1; cnt<=cnt+1; end
    2'b01: begin rp<=rp+1; cnt<=cnt-1; end
    2'b11: begin mem[wp]<=din; wp<=wp+1; rp<=rp+1; end
    default: ;
   endcase
  end
 end
endmodule

